begin;
create table public.atlas_memories(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),executive_identity_id uuid not null references public.executive_identities(id),category text not null,statement text not null,importance text not null,confidence text not null check(confidence in('Low','Moderate','High','Very High')),lifecycle text not null check(lifecycle in('Active','Confirmed','Questionable','Superseded','Archived','Forgotten')),reason_codes text[] not null default '{}',missing_evidence text[] not null default '{}',observed_at timestamptz not null,version integer not null default 1 check(version>0),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),archived_at timestamptz,unique(workspace_id,domain_id),unique(workspace_id,id));
create table public.atlas_memory_evidence(id uuid primary key,workspace_id uuid not null references public.workspaces(id),memory_id uuid not null,source_type text not null,source_record_id text not null,summary text not null,observed_at timestamptz not null,confirmed boolean not null,contradicts boolean not null default false,created_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),foreign key(workspace_id,memory_id) references public.atlas_memories(workspace_id,id));
create table public.atlas_memory_relationships(id uuid primary key,workspace_id uuid not null references public.workspaces(id),from_memory_id uuid not null,to_memory_id uuid not null,relationship_kind text not null check(relationship_kind in('Supports','Contradicts','Supersedes','Related')),created_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),foreign key(workspace_id,from_memory_id) references public.atlas_memories(workspace_id,id),foreign key(workspace_id,to_memory_id) references public.atlas_memories(workspace_id,id),check(from_memory_id<>to_memory_id));
create table public.atlas_memory_snapshots(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),sequence_number bigint not null check(sequence_number>=0),occurred_at timestamptz not null,recorded_at timestamptz not null default now(),correlation_id uuid not null,payload jsonb not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),version integer not null default 1,archived_at timestamptz,unique(workspace_id,domain_id),unique(workspace_id,sequence_number));
create table public.atlas_memory_audits(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),sequence_number bigint not null check(sequence_number>=0),occurred_at timestamptz not null,recorded_at timestamptz not null default now(),correlation_id uuid not null,memory_id uuid not null,event_type text not null,reason_code text not null,evidence_ids text[] not null default '{}',payload jsonb not null default '{}',created_at timestamptz not null default now(),updated_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),version integer not null default 1,archived_at timestamptz,foreign key(workspace_id,memory_id) references public.atlas_memories(workspace_id,id),unique(workspace_id,domain_id),unique(workspace_id,sequence_number));
do $$declare t text;begin foreach t in array array['atlas_memories','atlas_memory_evidence','atlas_memory_relationships','atlas_memory_snapshots','atlas_memory_audits'] loop execute format('alter table public.%I enable row level security',t);execute format('create policy %I on public.%I for select to authenticated using(public.is_active_workspace_member(workspace_id))',t||'_read',t);execute format('create policy %I on public.%I for insert to authenticated with check(public.is_active_workspace_member(workspace_id))',t||'_insert',t);end loop;end$$;
do $$declare t text;begin foreach t in array array['atlas_memories','atlas_memory_evidence','atlas_memory_relationships'] loop execute format('create policy %I on public.%I for update to authenticated using(public.is_active_workspace_member(workspace_id)) with check(public.is_active_workspace_member(workspace_id))',t||'_update',t);end loop;end$$;
do $$declare t text;begin foreach t in array array['atlas_memory_snapshots','atlas_memory_audits'] loop execute format('create trigger %I before update or delete on public.%I for each row execute function public.reject_append_only_mutation()',t||'_append_only',t);end loop;end$$;
grant select,insert,update on public.atlas_memories,public.atlas_memory_evidence,public.atlas_memory_relationships to authenticated;grant select,insert on public.atlas_memory_snapshots,public.atlas_memory_audits to authenticated;revoke delete on all tables in schema public from authenticated;revoke all on all tables in schema public from anon;
create index atlas_memories_workspace_status_idx on public.atlas_memories(workspace_id,lifecycle,observed_at desc);create index atlas_memory_evidence_memory_idx on public.atlas_memory_evidence(workspace_id,memory_id);create index atlas_memory_snapshots_sequence_idx on public.atlas_memory_snapshots(workspace_id,sequence_number desc);create index atlas_memory_audits_memory_idx on public.atlas_memory_audits(workspace_id,memory_id,sequence_number desc);
commit;
